// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE: db_crear_consulta solo registra o recupera una consulta.
// NO consulta disponibilidad.
// NO bloquea fechas.
// NO crea pre-reservas.
// Esas responsabilidades son de db_crear_prereserva.
//
// ⚠️  SHEETS_ID — reemplazar __SHEETS_ID__ con el ID real del Sheets
// Si el Sheet cambia, actualizar aquí y en todos los nodos
// Google Sheets del workflow.
// Valor actual: __SHEETS_ID__
//
// ⚠️  CREDENCIALES
// credential id (__CREDENTIAL_ID__) específico de esta instancia n8n.
// NO portable. Sanitizar antes de subir a GitHub:
//   - "id" en cada bloque credentials → "__CREDENTIAL_ID__"
//   - SHEETS_ID → "__SHEETS_ID__"
//
// ⚠️  ID_CONSULTA — estrategia actual: max + 1
// Para DEV y baja concurrencia esto es suficiente.
// Para alta concurrencia o producción con múltiples ejecuciones
// simultáneas, migrar a id tipo CON-<timestamp> o UUID para
// eliminar la race condition entre lectura del max y escritura.
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID      = '__SHEETS_ID__'; // __ENTORNO__
const CANALES_VALIDOS = ['whatsapp', 'instagram', 'web', 'manual'];

// ── DEV_INPUT ─────────────────────────────────────────────────
// Editar estos valores para cada prueba en DEV.
// Se usan SOLO si el Manual Trigger viene vacío (sin payload).
// En producción el input vendrá del Webhook con datos reales.
const DEV_INPUT = {
  canal:               'whatsapp',
  id_contacto_externo: '__TELEFONO_EJEMPLO__',
  id_huesped:          null,
  fecha_in_tentativa:  '2026-07-01',
  fecha_out_tentativa: '2026-07-03',
  personas_tentativa:  2,
  source_event:        'manual_dev'
};
// ─────────────────────────────────────────────────────────────

// Leer input real del trigger; si viene vacío usar DEV_INPUT
const raw            = $input.first()?.json ?? {};
const usandoDEVInput = !raw.canal && !raw.id_contacto_externo;
const input          = usandoDEVInput ? DEV_INPUT : raw;

const canal               = String(input.canal               ?? '').trim();
const id_contacto_externo = String(input.id_contacto_externo ?? '').trim();
const id_huesped          = input.id_huesped          ?? null;
const fecha_in_tentativa  = input.fecha_in_tentativa  ?? null;
const fecha_out_tentativa = input.fecha_out_tentativa ?? null;
const personas_tentativa  = input.personas_tentativa  ?? null;
const source_event        = String(input.source_event ?? 'manual_dev').trim();

// ── PASO 1: Validaciones ─────────────────────────────────────
const errores = [];

if (!CANALES_VALIDOS.includes(canal)) {
  errores.push(`canal inválido: '${canal}'. Valores aceptados: ${CANALES_VALIDOS.join(', ')}`);
}

if (!id_contacto_externo) {
  errores.push('id_contacto_externo es obligatorio y no puede estar vacío');
}

if (fecha_in_tentativa && fecha_out_tentativa) {
  const fi = new Date(fecha_in_tentativa  + 'T12:00:00Z');
  const fo = new Date(fecha_out_tentativa + 'T12:00:00Z');
  if (isNaN(fi.getTime()))  errores.push('fecha_in_tentativa inválida');
  if (isNaN(fo.getTime()))  errores.push('fecha_out_tentativa inválida');
  if (!isNaN(fi.getTime()) && !isNaN(fo.getTime()) && fo <= fi) {
    errores.push('fecha_out_tentativa debe ser posterior a fecha_in_tentativa');
  }
}

if (errores.length > 0) {
  // Retornar error sin _validado:true para que el IF lo corte
  return [{ json: {
    ok:       false,
    error:    'input_invalido',
    detalle:  errores,
    _validado: false
  }}];
}

// ── Normalizar ────────────────────────────────────────────────
const id_contacto_normalizado = id_contacto_externo.includes('@')
  ? id_contacto_externo.toLowerCase()
  : id_contacto_externo;

return [{ json: {
  SHEETS_ID,
  canal,
  id_contacto_externo: id_contacto_normalizado,
  id_huesped,
  fecha_in_tentativa:  fecha_in_tentativa  ?? '',
  fecha_out_tentativa: fecha_out_tentativa ?? '',
  personas_tentativa:  personas_tentativa  ?? '',
  source_event,
  ts_inicio:         new Date().toISOString(),
  _validado:         true,
  _usando_dev_input: usandoDEVInput
}}];

// Input inválido — devolver output final consistente.
// NO escribe LOG_CAMBIOS.
const data = $input.first().json;
return [{ json: {
  ok:      data.ok,
  error:   data.error,
  detalle: data.detalle
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Verificar Idempotencia
// ═══════════════════════════════════════════════════════════════
// PASO 2: Buscar si existe una CONSULTA activa RECIENTE para
// este id_contacto_externo.
//
// Condiciones para reutilizar una consulta existente:
//   1. id_contacto_externo coincide
//   2. estado_conversacion NOT IN ('cerrada', 'derivada_a_humano')
//   3. updated_at o ultimo_mensaje_at o created_at dentro de 24 hs
//
// Si existe consulta activa reciente → retornarla (idempotencia)
// Si existe consulta activa pero vieja → crear nueva de todas formas
// Si no existe ninguna → crear nueva
//
// PASO 3: Calcular próximo id_consulta = max + 1
// ⚠️  Race condition posible en alta concurrencia.
// Para producción con carga alta, migrar a CON-<timestamp> o UUID.
//
// ROBUSTEZ — hoja CONSULTAS vacía:
// Agg CONSULTAS puede devolver cualquiera de estos casos:
//   - .json.data inexistente  → tratado como []
//   - .json.data = []         → sin filas
//   - .json.data = [{}]       → fila vacía por alwaysOutputData
//   - .json.data = [{...}]    → filas reales
// En todos los casos, consultas queda como array limpio de filas
// con al menos un campo no vacío (id_consulta o id_contacto_externo).
// Resultado cuando hoja vacía: consultas = [], maxId = 0, nuevo_id = 1.
// ═══════════════════════════════════════════════════════════════

const inputData = $('Resolver Input').first().json;

// ── Normalizar el output de Agg CONSULTAS ────────────────────
// Defensivo ante todos los casos posibles de hoja vacía.
const aggJson = $('Agg CONSULTAS').first()?.json ?? {};
const rawData = aggJson.data;

const consultas = (Array.isArray(rawData) ? rawData : [])
  .filter(c => {
    // Descartar nulls, undefined y objetos completamente vacíos
    if (!c || typeof c !== 'object') return false;
    const keys = Object.keys(c);
    if (keys.length === 0) return false;
    // Descartar filas sin ningún campo identificable
    // (caso: alwaysOutputData inyecta {} que puede tener keys vacías)
    const tieneContenido = keys.some(k => {
      const v = c[k];
      return v !== null && v !== undefined && String(v).trim() !== '';
    });
    return tieneContenido;
  });

// ── Idempotencia con ventana de 24 horas ─────────────────────
const ESTADOS_INACTIVOS = ['cerrada', 'derivada_a_humano'];
const VENTANA_MS        = 24 * 60 * 60 * 1000;
const ahora             = new Date();
const limite            = new Date(ahora.getTime() - VENTANA_MS);

const consultaExistente = consultas.find(c => {
  // Condición 1: mismo contacto
  if (String(c.id_contacto_externo ?? '').trim() !== inputData.id_contacto_externo) return false;

  // Condición 2: estado activo
  if (ESTADOS_INACTIVOS.includes(String(c.estado_conversacion ?? '').trim())) return false;

  // Condición 3: reciente (dentro de 24 horas)
  const tsStr = c.updated_at || c.ultimo_mensaje_at || c.created_at || '';
  if (!tsStr || String(tsStr).trim() === '') return false;
  const ts = new Date(String(tsStr).trim());
  if (isNaN(ts.getTime())) return false;
  return ts >= limite;
});

if (consultaExistente) {
  return [{ json: {
    _accion:             'reutilizar_existente',
    id_consulta:         parseInt(String(consultaExistente.id_consulta), 10),
    estado_conversacion: consultaExistente.estado_conversacion,
    canal:               consultaExistente.canal,
    id_contacto_externo: consultaExistente.id_contacto_externo,
    source_event:        inputData.source_event
  }}];
}

// ── Calcular próximo id_consulta ──────────────────────────────
const ids = consultas
  .map(c => parseInt(String(c.id_consulta ?? ''), 10))
  .filter(n => !isNaN(n) && n > 0);
const maxId             = ids.length > 0 ? Math.max(...ids) : 0;
const nuevo_id_consulta = maxId + 1;

return [{ json: {
  _accion:            'crear_nueva',
  inputData,
  nuevo_id_consulta
}}];

// ── Rama: consulta existente reutilizada ─────────────────────
// Preparar LOG y output unificado.
const data  = $input.first().json;
const ahora = new Date();

return [{ json: {
  _para_log: {
    id_log:           `LOG-CONSULTA-${ahora.getTime()}`,
    fecha_hora:        ahora.toISOString(),
    tabla_afectada:   'CONSULTAS',
    id_registro:      String(data.id_consulta),
    campo_modificado: 'consulta_reutilizada',
    valor_anterior:   '',
    valor_nuevo:      String(data.id_consulta),
    modificado_por:   'n8n',
    source_event:     data.source_event,
    nivel:            'info',
    detalle: JSON.stringify({
      id_consulta:         data.id_consulta,
      canal:               data.canal,
      id_contacto_externo: data.id_contacto_externo,
      motivo:              'consulta_activa_reciente_existente'
    })
  },
  _output: {
    ok:                  true,
    es_nueva:            false,
    id_consulta:         data.id_consulta,
    estado_conversacion: data.estado_conversacion,
    accion:              'existente_reutilizada',
    source_event:        data.source_event
  }
}}];

// Output final — rama reutilización
const data = $('Prep Reutilizar').first().json;
return [{ json: data._output }];

// ── Rama: crear consulta nueva ───────────────────────────────
const data  = $input.first().json;
const { inputData, nuevo_id_consulta } = data;
const ahora = new Date().toISOString();

return [{ json: {
  id_consulta:          nuevo_id_consulta,
  canal:                inputData.canal,
  id_contacto_externo:  inputData.id_contacto_externo,
  id_huesped:           inputData.id_huesped ?? '',
  estado_conversacion:  'inicio',
  id_cabana_tentativa:  '',
  fecha_in_tentativa:   inputData.fecha_in_tentativa  ?? '',
  fecha_out_tentativa:  inputData.fecha_out_tentativa ?? '',
  personas_tentativa:   inputData.personas_tentativa  ?? '',
  ultimo_mensaje_at:    ahora,
  contexto_json:        '',
  tokens_json:          '',
  motivo_derivacion:    '',
  source_event:         inputData.source_event,
  created_at:           ahora,
  updated_at:           ahora
}}];

// Preparar LOG para consulta nueva
const fila  = $('Preparar Fila CONSULTAS').first().json;
const ahora = new Date();

return [{ json: {
  id_log:           `LOG-CONSULTA-${ahora.getTime()}`,
  fecha_hora:        ahora.toISOString(),
  tabla_afectada:   'CONSULTAS',
  id_registro:      String(fila.id_consulta),
  campo_modificado: 'estado_conversacion',
  valor_anterior:   '',
  valor_nuevo:      'inicio',
  modificado_por:   'n8n',
  source_event:     fila.source_event,
  nivel:            'info',
  detalle: JSON.stringify({
    id_consulta:         fila.id_consulta,
    canal:               fila.canal,
    id_contacto_externo: fila.id_contacto_externo,
    fecha_in_tentativa:  fila.fecha_in_tentativa,
    fecha_out_tentativa: fila.fecha_out_tentativa,
    personas_tentativa:  fila.personas_tentativa
  })
}}];

// Output final — rama nueva.
// Mismo formato que la rama de reutilización.
const fila = $('Preparar Fila CONSULTAS').first().json;
return [{ json: {
  ok:                  true,
  es_nueva:            true,
  id_consulta:         fila.id_consulta,
  estado_conversacion: fila.estado_conversacion,
  accion:              'creada',
  source_event:        fila.source_event
}}];
